<?php include __DIR__.'/_init.php'; $search='%'.($_GET['q']??'').'%';$q=$db->prepare('SELECT * FROM students WHERE full_name LIKE ? OR email LIKE ? ORDER BY id DESC');$q->execute([$search,$search]);$rows=$q->fetchAll(); ?><h2>Students</h2><form><input name="q" placeholder="Search"></form><table border="1"><tr><th>Name</th><th>Email</th><th>Profession</th><th>Status</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['email'])?></td><td><?=e($r['profession'])?></td><td><?=e($r['status'])?></td></tr><?php endforeach;?></table>
